  if (/^https?:\/\//i.test(url)) return url;

  if (typeof window === "undefined") return url;

  if (url.startsWith("//")) return `${window.location.protocol}${url}`;
  if (url.startsWith("/")) return `${window.location.origin}${url}`;

  return url;
};

